import{_ as e,o as t,c as a,a2 as o}from"./chunks/framework.Bix3-HpO.js";const d=JSON.parse('{"title":"Affiliate Links","description":"SpinokoGeo Affiliate Links","frontmatter":{"title":"Affiliate Links","description":"SpinokoGeo Affiliate Links","weight":40,"extra":{"order":40},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko-geo/affiliate-links"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko-geo/affiliate-links"}],["meta",{"property":"og:title","content":"Affiliate Links"}],["meta",{"property":"og:description","content":"SpinokoGeo Affiliate Links"}],["meta",{"name":"twitter:title","content":"Affiliate Links"}],["meta",{"name":"twitter:description","content":"SpinokoGeo Affiliate Links"}]]},"headers":[],"relativePath":"docs/spinoko-geo/affiliate-links.md","filePath":"docs/spinoko-geo/affiliate-links.md"}'),n={name:"docs/spinoko-geo/affiliate-links.md"};function l(s,i,f,r,c,k){return t(),a("div",null,[...i[0]||(i[0]=[o('<h1 id="affiliate-links" tabindex="-1">Affiliate Links <a class="header-anchor" href="#affiliate-links" aria-label="Permalink to &quot;Affiliate Links&quot;">​</a></h1><p>SpinokoGeo plugin allows you to set country-specific affiliate links for each casino review. This means you can have different affiliate links for different countries, making your affiliate marketing more targeted and effective.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Geo Affiliate Links feature enables you to:</p><ul><li>Set different affiliate links for different countries</li><li>Use a default affiliate link as fallback</li><li>Manage all country-specific links in one place</li><li>Automatically serve the correct link based on visitor&#39;s location</li></ul><h3 id="setting-up-geo-affiliate-links" tabindex="-1">Setting Up Geo Affiliate Links <a class="header-anchor" href="#setting-up-geo-affiliate-links" aria-label="Permalink to &quot;Setting Up Geo Affiliate Links&quot;">​</a></h3><p>To set up country-specific affiliate links for a casino review:</p><ul><li>Edit the casino review post</li><li>Look for the &quot;🌍 Geo Affiliate Links&quot; tab in the editor</li><li>Enter the affiliate link for each country you want to target</li><li>Leave any country&#39;s field empty to use the default affiliate link instead</li></ul><p><img src="https://media.dinomatic.com/images/docs/spinoko-geo/spinoko-geo-affiliate-links.jpg" alt="SpinokoGeo Affiliate Links"></p><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><p>The plugin automatically detects the visitor&#39;s country using Cloudflare&#39;s IP Geolocation service and serves the appropriate affiliate link. If no country-specific link is set, it falls back to the default affiliate link.</p>',11)])])}const u=e(n,[["render",l]]);export{d as __pageData,u as default};
